def group_consecutive(iterable, key=None):
    if key is None:
        key = lambda x: x
    it = iter(iterable)
    try:
        first = next(it)
    except StopIteration:
        return
    current_key = key(first)
    bucket = [first]
    for item in it:
        k = key(item)
        if k == current_key:
            bucket.append(item)
        else:
            yield (current_key, bucket)
            current_key = k
            bucket = [item]
    yield (current_key, bucket)
